settingsManagementPage.content:
// ── Replace @@REPLACE@@ (PascalCase) & @@replace@@ (camelCase) with entity name ──
// Copy to: src/pages/settings/@@REPLACE@@.tsx
// Sections: 1·header 2·filter-bar 3·table 4·create-edit-modal 5·delete-modal 6·bulk-update-modal

import { Button, Checkbox, Form, Input, InputNumber, message, Modal, DatePicker, Switch } from 'antd';
import { useCallback, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { DeleteOutlined, EditOutlined, PlusOutlined } from '@ant-design/icons';
import { @@replace@@UseCase } from '@/domain/use-cases/@@replace@@.use-case';
import usePaging from '@/presenters/components/core/table/hooks/use-paging';
import { useDialog } from '@/domain/hooks/use-dialog';
import {
  @@REPLACE@@,
  @@REPLACE@@Filter,
  @@REPLACE@@Payload,
} from '@/domain/models/@@replace@@';
import SelectFilter from '@/presenters/components/common/SelectFilter';
import type { ColumnsType } from 'antd/es/table';
import TablePaging from '@/presenters/components/core/table';
import dayjs from 'dayjs';
import { FORMAT_DATE_DEFAULT } from '@/configs';
import { getDateTime } from '@/utils';

const @@REPLACE@@Management = () => {
  const { t } = useTranslation();
  const [selectedStatus, setSelectedStatus] = useState<string[]>([]);
  const [loadingBtn, setLoadingBtn] = useState(false);
  const { open, selected, onClose, onShow } = useDialog<@@REPLACE@@>();
  const [search, setSearch] = useState<string>('');
  const [isAllActive, setIsAllActive] = useState(false);
  const [headerSwitchModalVisible, setHeaderSwitchModalVisible] = useState(false);
  const [headerSwitchValue, setHeaderSwitchValue] = useState(false);
  const [headerSwitchLoading, setHeaderSwitchLoading] = useState(false);
  const {
    open: openDelete,
    selected: selectedDelete,
    onClose: onCloseDelete,
    onShow: onShowDelete,
  } = useDialog<@@REPLACE@@>();
  const [form] = Form.useForm();

  // SECTION 1 · Row-level isActive toggle
  const onChangeSwitch = async (record: @@REPLACE@@, isActive: boolean) => {
    try {
      setLoadingBtn(true);
      await @@replace@@UseCase.update({ ...record, isActive: !isActive });
      message.success(isActive ? t('common.deactivateSuccess') : t('common.activateSuccess'));
      handleReloadCurrentOffset();
    } catch (error: any) {
      console.error('Error updating status:', error);
      message.error(error?.message ?? t('common.errorToast'));
    } finally {
      setLoadingBtn(false);
    }
  };

  // SECTION 2 · Header-level bulk toggle (queues confirmation modal)
  const handleHeaderSwitchChange = useCallback((checked: boolean) => {
    setHeaderSwitchValue(checked);
    setHeaderSwitchModalVisible(true);
  }, []);

  const handleConfirmHeaderSwitch = async () => {
    try {
      setHeaderSwitchLoading(true);
      await @@replace@@UseCase.updateAll(!isAllActive);
      message.success(t('common.activateAllSuccess'));
      handleReloadCurrentOffset();
    } catch (error: any) {
      console.error('Error updating all:', error);
      message.error(error?.message ?? t('common.errorToast'));
    } finally {
      setHeaderSwitchLoading(false);
      setHeaderSwitchModalVisible(false);
    }
  };

  // SECTION 3 · Columns — keep isActive + action columns; replace TODO block with entity fields
  const columns = useMemo<ColumnsType<@@REPLACE@@>>(
    () => [
      {
        title: t('@@replace@@.name'),
        dataIndex: 'name',
        key: 'name',
        width: 150,
        sorter: (a, b) => a.name.localeCompare(b.name),
      },
      // TODO: add entity-specific columns here
      {
        title: t('@@replace@@.startDate'),
        dataIndex: 'startDate',
        key: 'startDate',
        width: 150,
        render: (startDate: string) => getDateTime(startDate, FORMAT_DATE_DEFAULT),
      },
      {
        title: t('@@replace@@.endDate'),
        dataIndex: 'endDate',
        key: 'endDate',
        width: 150,
        render: (endDate: string) => getDateTime(endDate, FORMAT_DATE_DEFAULT),
      },
      {
        title: (
          <div className='flex items-center gap-2'>
            <Switch onChange={handleHeaderSwitchChange} checked={isAllActive} />
            <span>{t('@@replace@@.active')}</span>
          </div>
        ),
        dataIndex: 'isActive',
        key: 'isActive',
        width: 200,
        render: (isActive: boolean, record) => (
          <Switch checked={isActive} onChange={() => onChangeSwitch(record, isActive)} />
        ),
      },
      {
        title: '',
        dataIndex: 'action',
        key: 'action',
        width: 100,
        render: (_: string, record: @@REPLACE@@) => (
          <div className='flex gap-[8px] justify-end'>
            <Button
              type='text'
              icon={<EditOutlined />}
              onClick={() => {
                onShow(record);
                form.setFieldsValue({
                  ...record,
                  startDate: record.startDate ? dayjs(record.startDate) : null,
                  endDate: record.endDate ? dayjs(record.endDate) : null,
                });
              }}
            />
            <Button type='text' icon={<DeleteOutlined />} onClick={() => onShowDelete(record)} />
          </div>
        ),
      },
    ],
    [t, isAllActive, handleHeaderSwitchChange],
  );

  // SECTION 4 · Fetch — setIsAllActive from metadata
  const fetchData = useCallback(async (params?: @@REPLACE@@Filter) => {
    try {
      const response = await @@replace@@UseCase.getList({
        ...params,
        isActiveOnly: typeof params?.isActiveOnly === 'undefined' ? true : params.isActiveOnly === 'true',
      });
      setIsAllActive(response.data?.metadata?.isAllActive || false);
      return {
        list: response.data?.items || [],
        total: response.data?.items?.length || 0,
      };
    } catch (error) {
      console.error('Error fetching data:', error);
      return { list: [], total: 0 };
    }
  }, []);

  const { dataSource, total, handleFilterChange, handleReloadCurrentOffset, isLoading } = usePaging({
    getDataOffset: fetchData,
    idKey: 'id',
    initState: { filter: { isActiveOnly: undefined, searchText: search } },
    defaultPageIndex: 0,
  });

  const keyRender = useMemo(() => JSON.stringify([total, isAllActive]), [total, isAllActive]);

  // SECTION 5 · Create / Update
  const onFinish = async (values: @@REPLACE@@Payload) => {
    try {
      setLoadingBtn(true);
      if (selected) {
        await @@replace@@UseCase.update({ ...values, id: selected.id });
        message.success(t('@@replace@@.updateSuccess'));
      } else {
        await @@replace@@UseCase.create({ ...values, seqOrder: dataSource[dataSource.length - 1]?.seqOrder || 0 });
        message.success(t('@@replace@@.createSuccess'));
      }
      onClose();
      handleReloadCurrentOffset();
      form.resetFields();
    } catch (error: any) {
      console.error('Error saving:', error);
      message.error(error?.message ?? t('common.errorToast'));
    } finally {
      setLoadingBtn(false);
    }
  };

  // SECTION 6 · Delete
  const onDelete = async () => {
    try {
      if (!selectedDelete) return;
      setLoadingBtn(true);
      await @@replace@@UseCase.delete(selectedDelete?.id);
      message.success(t('@@replace@@.deleteSuccess'));
      onCloseDelete();
      handleReloadCurrentOffset();
    } catch (error: any) {
      console.error('Error deleting:', error);
      message.error(error?.message ?? t('common.errorToast'));
    } finally {
      setLoadingBtn(false);
    }
  };

  return (
    <div className='px-4'>
      {/* SLOT 1 · Header */}
      <div className='-mx-[12px]'>
        <div className='flex items-center justify-between px-3 py-3'>
          <h3 className='text-heading-03 font-heading-03 text-on-surface-strong'>{t('@@replace@@.title')}</h3>
          <Button
            color='default'
            variant='solid'
            icon={<PlusOutlined className='anticon-plus' />}
            onClick={() => { form.setFieldsValue({ isActive: true }); onShow(); }}
          >
            {t('common.addNew')}
          </Button>
        </div>
      </div>

      <div className='container'>
        {/* SLOT 2 · Filter bar */}
        <div className='flex items-center gap-2 mb-4'>
          <Input.Search
            placeholder={t('@@replace@@.search')}
            allowClear
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            style={{ maxWidth: 400 }}
            onSearch={(value) => handleFilterChange({ searchText: value, isActiveOnly: selectedStatus?.[0] })}
            onKeyDown={(e) => {
              if (e.key === 'Enter') {
                handleFilterChange({ searchText: (e.target as HTMLInputElement).value, isActiveOnly: selectedStatus?.[0] });
              }
            }}
          />
          <SelectFilter
            label={!selectedStatus?.length ? t('@@replace@@.activeOnly') : ''}
            selected={selectedStatus ? [selectedStatus.toString()] : []}
            options={[
              { value: true, label: t('@@replace@@.activeOnly') },
              { value: false, label: t('@@replace@@.all') },
            ]}
            isMulti={false}
            allowClear
            onFilter={(value) => {
              handleFilterChange({ searchText: search, isActiveOnly: value?.[0] });
              setSelectedStatus(value);
            }}
          />
        </div>

        {/* SLOT 3 · Table */}
        <div>
          <TablePaging
            key={keyRender}
            scroll={{ x: 'max-content' }}
            disabledPaging
            columns={columns as any[]}
            tableClassName='custom-table border border-solid border-[#E0E0E0]'
            rowKey='id'
            dataSource={dataSource}
            isLoading={isLoading}
          />
        </div>
      </div>

      {/* SLOT 4 · Create/Edit Modal */}
      <Modal
        title={
          <span className='font-roboto font-bold text-[20px] leading-6 tracking-normal align-middle'>
            {selected?.id ? t('@@replace@@.update') : t('@@replace@@.create')}
          </span>
        }
        closable={{ 'aria-label': 'Custom Close Button' }}
        open={open}
        onCancel={onClose}
        footer={null}
      >
        <Form form={form} className='mt-4' layout='vertical' onFinish={onFinish}>
          {/* TODO: replace form fields below with entity-specific fields */}
          <div className='flex gap-4'>
            <Form.Item
              label={t('@@replace@@.name')}
              name='name'
              rules={[{ required: true }, { max: 255 }]}
              className='w-1/2'
            >
              <Input placeholder={t('@@replace@@.name')} maxLength={255} />
            </Form.Item>
          </div>

          <div className='flex gap-4'>
            <Form.Item
              label={t('@@replace@@.startDate')}
              name='startDate'
              className='w-1/2'
              rules={[{ required: true }]}
            >
              <DatePicker className='w-full' format={FORMAT_DATE_DEFAULT} />
            </Form.Item>

            <Form.Item
              label={t('@@replace@@.endDate')}
              name='endDate'
              className='w-1/2'
              rules={[{
                validator: (_, value) => {
                  const startDate = form.getFieldValue('startDate');
                  if (!value || !startDate) return Promise.resolve();
                  if (value.isBefore(startDate, 'day'))
                    return Promise.reject(t('common.expiryDateMustBeAfterStartDate'));
                  return Promise.resolve();
                },
              }]}
            >
              <DatePicker className='w-full' format={FORMAT_DATE_DEFAULT} />
            </Form.Item>
          </div>

          <Form.Item
            label={t('@@replace@@.description')}
            name='description'
            rules={[{ required: true }, { max: 1000 }]}
          >
            <Input.TextArea rows={4} placeholder={t('@@replace@@.descriptionPlaceholder')} maxLength={1000} />
          </Form.Item>

          <Form.Item name='isActive' valuePropName='checked' initialValue={true}>
            <Checkbox>{t('common.activate')}</Checkbox>
          </Form.Item>

          <div className='flex justify-end gap-2 mt-[40px]'>
            <Button className='min-w-[80px] bg-[#EFEFEF] rounded-[4px]' disabled={loadingBtn} onClick={onClose}>
              {t('common.cancel')}
            </Button>
            <Button color='default' variant='solid' className='min-w-[80px]' loading={loadingBtn} htmlType='submit'>
              {!selected?.id ? t('common.addNew') : t('common.save')}
            </Button>
          </div>
        </Form>
      </Modal>

      {/* SLOT 5 · Delete Confirm Modal */}
      <Modal
        title={t('@@replace@@.deleteTitle')}
        closable={{ 'aria-label': 'Custom Close Button' }}
        open={openDelete}
        onCancel={onCloseDelete}
        onOk={onDelete}
        okButtonProps={{ loading: loadingBtn, color: 'red', variant: 'solid', style: { minWidth: 80 } }}
        cancelButtonProps={{ disabled: loadingBtn, style: { minWidth: 80, backgroundColor: '#EFEFEF' } }}
        okText={t('common.confirm')}
        cancelText={t('common.cancel')}
      >
        <p dangerouslySetInnerHTML={{ __html: t('common.warningDelete', { name: selectedDelete?.name }) }} />
      </Modal>

      {/* SLOT 6 · Bulk Update Confirm Modal */}
      <Modal
        title={t('@@replace@@.updateTitle')}
        open={headerSwitchModalVisible}
        onCancel={() => setHeaderSwitchModalVisible(false)}
        onOk={handleConfirmHeaderSwitch}
        okButtonProps={{ loading: headerSwitchLoading, style: { minWidth: 80 }, variant: 'solid', color: 'default' }}
        cancelButtonProps={{ disabled: headerSwitchLoading, style: { minWidth: 80, backgroundColor: '#EFEFEF' } }}
        okText={t('common.confirm')}
        cancelText={t('common.cancel')}
      >
        <p>
          {t('@@replace@@.confirmAllUpdate', {
            value: headerSwitchValue ? t('common.activate') : t('common.inactivate'),
          })}
        </p>
      </Modal>
    </div>
  );
};

export default @@REPLACE@@Management;
